### **Schritt 2: Prüfe die `gdl-ui-studio/backend/src/Controllers/ParameterController.php`**

**Sicherstellen, dass der Controller den korrekten Namespace hat:**
Der Namespace `App\Controllers` ist in der `composer.json` definiert und muss exakt so im Controller stehen.

**Überprüfe, ob deine `gdl-ui-studio/backend/src/Controllers/ParameterController.php` *genau* so aussieht:**

```php
<?php
// gdl-ui-studio/backend/src/Controllers/ParameterController.php

namespace App\Controllers; // WICHTIG: Dieser Namespace muss korrekt sein

use Psr\Http\Message\ResponseInterface as Response;
use Psr\Http\Message\ServerRequestInterface as Request;
// use App\Models\Parameter; // Model ist für diese einfache Version noch nicht direkt nötig, PDO reicht
use \PDO; // Direkt PDO verwenden

class ParameterController
{
    protected PDO $db; // Type Hint für PDO

    // Constructor wird über Dependency Injection von PHP-DI befüllt
    public function __construct(PDO $db) // Type Hint für PDO
    {
        $this->db = $db;
    }

    public function importXml(Request $request, Response $response): Response
    {
        $data = $request->getParsedBody();
        $xmlContent = $data['xml_content'] ?? null;
        $projectName = $data['project_name'] ?? 'Default Project'; // Default name if not provided

        if (empty($xmlContent)) {
            return $response->withStatus(400)->withJson(['error' => 'No XML content provided.']);
        }

        try {
            // Start Transaction
            $this->db->beginTransaction();

            // First, create or get the project
            // ON DUPLICATE KEY UPDATE: nur das updated_at aktualisieren, nicht den Namen
            $stmt = $this->db->prepare("INSERT INTO projects (name) VALUES (?) ON DUPLICATE KEY UPDATE updated_at=CURRENT_TIMESTAMP");
            $stmt->execute([$projectName]);
            $projectId = $this->db->lastInsertId();
            // If project already existed, we need to fetch its ID
            if ($projectId == 0) { // lastInsertId() returns 0 if no new row was inserted by ON DUPLICATE KEY UPDATE
                $stmt = $this->db->prepare("SELECT id FROM projects WHERE name = ?");
                $stmt->execute([$projectName]);
                $projectId = $stmt->fetchColumn();
            }

            // Important: Use the fetched or created projectId consistently
            if (!$projectId) {
                 throw new \Exception("Could not determine project ID.");
            }

            // Temporary: Delete existing parameters for this project to avoid duplicates during testing
            // Ensure child tables are cleared first due to foreign key constraints
            $deleteTranslationsStmt = $this->db->prepare("DELETE FROM parameter_translations WHERE param_id IN (SELECT id FROM parameters WHERE project_id = ?)");
            $deleteTranslationsStmt->execute([$projectId]);
            $deleteParametersStmt = $this->db->prepare("DELETE FROM parameters WHERE project_id = ?");
            $deleteParametersStmt->execute([$projectId]);


            $xml = simplexml_load_string($xmlContent);
            if ($xml === false) {
                // Get XML errors for better debugging
                $xmlErrors = libxml_get_errors();
                $errorMessages = array_map(fn($error) => $error->message, $xmlErrors);
                libxml_clear_errors();
                return $response->withStatus(400)->withJson(['error' => 'Invalid XML format: ' . implode(', ', $errorMessages)]);
            }

            // Make sure the <Parameters> tag exists
            if (!isset($xml->Parameters)) {
                throw new \Exception("XML is missing the <Parameters> root element.");
            }

            $sortOrder = 0;
            foreach ($xml->Parameters->children() as $gdlParameter) {
                $sortOrder++;
                $gdlName = (string)$gdlParameter['Name'];
                $gdlType = $gdlParameter->getName(); // Tag name is the type (Length, Boolean, etc.)

                // Description can be nested in CDATA
                $description = '';
                if (isset($gdlParameter->Description)) {
                    // Check if it's a SimpleXMLElement object before casting
                    if ($gdlParameter->Description instanceof \SimpleXMLElement) {
                        $description = (string)$gdlParameter->Description;
                    } else {
                        $description = (string)$gdlParameter->Description; // Fallback for simple string
                    }
                }

                $defaultValue = null; 
                // Handle different value types
                if (isset($gdlParameter->Value)) {
                    if ($gdlType === 'Dictionary') {
                        // Store Dictionary structure as JSON
                        $defaultValue = json_encode(simplexml_to_array($gdlParameter->Value));
                    } else {
                        $defaultValue = (string)$gdlParameter->Value;
                    }
                } elseif (isset($gdlParameter->ArrayValues)) {
                    // Store ArrayValues as JSON
                    $arrayValues = [];
                    foreach($gdlParameter->ArrayValues->children() as $aVal) {
                        $arrayValues[] = (string)$aVal;
                    }
                    $defaultValue = json_encode($arrayValues);
                }


                // Extract flags
                $isFixName = $gdlParameter->Fix ? true : false;
                $flagBold = false;
                $flagChild = false;
                $flagHidden = false;
                $flagUnique = false;

                if (isset($gdlParameter->Flags)) { // Only iterate if Flags exist
                    foreach ($gdlParameter->Flags->children() as $flag) {
                        switch ($flag->getName()) {
                            case 'ParFlg_BoldName': $flagBold = true; break;
                            case 'ParFlg_Child': $flagChild = true; break;
                            case 'ParFlg_Hidden': $flagHidden = true; break;
                            case 'ParFlg_Unique': $flagUnique = true; break;
                        }
                    }
                }

                // Simplified array type detection and dimensions for now
                $arrayType = 'None';
                $firstDim = 0;
                $secondDim = 0;
                if (isset($gdlParameter->ArrayValues)) {
                    $arrayType = ((string)$gdlParameter->ArrayValues['SecondDimension'] > 0) ? '2D' : '1D';
                    $firstDim = (int)$gdlParameter->ArrayValues['FirstDimension'];
                    $secondDim = (int)$gdlParameter->ArrayValues['SecondDimension'];
                }

                // Insert parameter
                $stmt = $this->db->prepare("
                    INSERT INTO parameters (project_id, gdl_name, gdl_type, default_value_json, is_fix_name, flag_bold, flag_child, flag_hidden, flag_unique, array_type, array_first_dim, array_second_dim, sort_order)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                ");
                $stmt->execute([
                    $projectId, $gdlName, $gdlType, $defaultValue,
                    $isFixName, $flagBold, $flagChild, $flagHidden, $flagUnique,
                    $arrayType, $firstDim, $secondDim, $sortOrder
                ]);
                $paramId = $this->db->lastInsertId();

                // Insert German description (and default to English if not provided in XML)
                $stmt = $this->db->prepare("
                    INSERT INTO parameter_translations (param_id, language_code, description)
                    VALUES (?, ?, ?)
                ");
                $stmt->execute([$paramId, 'de', $description]);

                // Add a default English translation
                $stmt = $this->db->prepare("
                    INSERT INTO parameter_translations (param_id, language_code, description)
                    VALUES (?, ?, ?) ON DUPLICATE KEY UPDATE description = VALUES(description)
                ");
                $stmt->execute([$paramId, 'en', $description]); // For now, English is same as German
            }

            $this->db->commit(); // Commit transaction

            return $response->withJson(['message' => 'Parameters imported successfully for project ' . $projectName . '.', 'projectId' => $projectId]);

        } catch (\PDOException $e) {
            $this->db->rollBack();
            error_log("DB Error during XML Import: " . $e->getMessage() . " - SQL: " . $stmt->queryString ?? 'N/A');
            return $response->withStatus(500)->withJson(['error' => 'Database error during import: ' . $e->getMessage()]);
        } catch (\Exception $e) {
            $this->db->rollBack();
            error_log("XML Import Error: " . $e->getMessage());
            return $response->withStatus(500)->withJson(['error' => 'Failed to import parameters: ' . $e->getMessage()]);
        }
    }

    // --- NEU: Methode zum Abrufen aller Parameter eines Projekts ---
    public function getProjectParameters(Request $request, Response $response, array $args): Response
    {
        $projectId = $args['projectId'] ?? null;

        if (!$projectId) {
            return $response->withStatus(400)->withJson(['error' => 'Project ID is required.']);
        }

        try {
            $stmt = $this->db->prepare("
                SELECT p.*, pt.language_code, pt.description, pt.values_list, pt.ui_tooltip
                FROM parameters p
                LEFT JOIN parameter_translations pt ON p.id = pt.param_id
                WHERE p.project_id = ?
                ORDER BY p.sort_order ASC
            ");
            $stmt->execute([$projectId]);
            $rawParams = $stmt->fetchAll(PDO::FETCH_ASSOC);

            // Group translations by parameter
            $parameters = [];
            foreach ($rawParams as $row) {
                $paramId = $row['id'];
                if (!isset($parameters[$paramId])) {
                    $parameters[$paramId] = [
                        'id' => $row['id'],
                        'gdl_name' => $row['gdl_name'],
                        'gdl_type' => $row['gdl_type'],
                        'function_group' => $row['function_group'],
                        'array_type' => $row['array_type'],
                        'array_first_dim' => $row['array_first_dim'],
                        'array_second_dim' => $row['array_second_dim'],
                        'default_value_json' => $row['default_value_json'],
                        'is_fix_name' => (bool)$row['is_fix_name'],
                        'flag_bold' => (bool)$row['flag_bold'],
                        'flag_child' => (bool)$row['flag_child'],
                        'flag_hidden' => (bool)$row['flag_hidden'],
                        'flag_unique' => (bool)$row['flag_unique'],
                        'ui_page' => $row['ui_page'],
                        'is_ui_element' => (bool)$row['is_ui_element'],
                        'ui_code' => $row['ui_code'],
                        'sort_order' => $row['sort_order'],
                        'created_at' => $row['created_at'],
                        'updated_at' => $row['updated_at'],
                        'translations' => []
                    ];
                }
                if ($row['language_code']) {
                    $parameters[$paramId]['translations'][] = [
                        'language_code' => $row['language_code'],
                        'description' => $row['description'],
                        'values_list' => $row['values_list'],
                        'ui_tooltip' => $row['ui_tooltip']
                    ];
                }
            }

            // Also fetch the project name
            $projectStmt = $this->db->prepare("SELECT name FROM projects WHERE id = ?");
            $projectStmt->execute([$projectId]);
            $projectName = $projectStmt->fetchColumn();


            return $response->withJson([
                'project_name' => $projectName,
                'parameters' => array_values($parameters) // Reset array keys
            ]);

        } catch (\Exception $e) {
            error_log("Error fetching parameters: " . $e->getMessage());
            return $response->withStatus(500)->withJson(['error' => 'Failed to fetch parameters: ' . $e->getMessage()]);
        }
    }
}

// Helper function to convert SimpleXMLElement to array (for Dictionary)
function simplexml_to_array(\SimpleXMLElement $xml): array
{
    $array = [];
    foreach ($xml->children() as $node) {
        $name = $node->getName();
        // Check if the node has children (is a nested dictionary or complex element)
        if ($node->children()->count() > 0) {
            $array[$name] = simplexml_to_array($node);
        } else {
            // Otherwise, it's a simple value
            $array[$name] = (string)$node;
        }
    }
    return $array;
}
