### **Die robustere Lösung: Individuelle ENV-Variablen als Container-Einträge definieren**

Wir werden die Umgebungsvariablen nicht direkt im `PDO`-Closure lesen, sondern sie als separate, benannte Einträge im Container definieren. Dann injizieren wir diese benannten Einträge in das `PDO`-Closure. Das gibt PHP-DI eine klare Anweisung.

**Hier ist der aktualisierte `gdl-ui-studio/backend/public/index.php` Code:**

```php
<?php
use Psr\Http\Message\ResponseInterface as Response;
use Psr\Http\Message\ServerRequestInterface as Request;
use Psr\Http\Server\RequestHandlerInterface as RequestHandler;
use Slim\Factory\AppFactory;
use DI\Container;
use Dotenv\Dotenv;

require __DIR__ . '/../vendor/autoload.php';

// Load .env file
if (file_exists(__DIR__ . '/../.env')) {
    $dotenv = Dotenv::createImmutable(__DIR__ . '/../');
    $dotenv->load(); // Lädt die Variablen in $_ENV und getenv()
}

// Create Container
$container = new Container();
AppFactory::setContainer($container);

// ###############################################################
// KRITISCH: Datenbank-Parameter als separate Container-Einträge definieren
// Dies stellt sicher, dass PHP-DI die Werte vor der PDO-Initialisierung auflöst.
// ###############################################################
$container->set('db.host', function () {
    return $_ENV['DB_HOST'] ?? 'localhost';
});
$container->set('db.name', function () {
    return $_ENV['DB_NAME'] ?? 'gdl_ui_studio_db';
});
$container->set('db.user', function () {
    return $_ENV['DB_USER'] ?? 'root';
});
$container->set('db.password', function () {
    return $_ENV['DB_PASSWORD'] ?? 'root';
});
// ###############################################################


// Set up database connection using the defined parameters
$container->set('db', function (
    string $dbHost,      // PHP-DI injiziert 'db.host' hier
    string $dbName,      // PHP-DI injiziert 'db.name' hier
    string $dbUser,      // PHP-DI injiziert 'db.user' hier
    string $dbPassword   // PHP-DI injiziert 'db.password' hier
) {
    $dsn = "mysql:host={$dbHost};dbname={$dbName};charset=utf8mb4";
    $pdo = new PDO($dsn, $dbUser, $dbPassword);
    $pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
    $pdo->setAttribute(PDO::ATTR_DEFAULT_FETCH_MODE, PDO::FETCH_ASSOC);
    return $pdo;
})
->addArguments([ // Explizit sagen, welche Container-Einträge injiziert werden sollen
    'db.host',
    'db.name',
    'db.user',
    'db.password'
]);


$app = AppFactory::create();

// ###############################################################
// KRITISCH: Slims Basis-Pfad explizit setzen (Beibehalten)
// ###############################################################
$app->setBasePath('/gdl-ui-studio/backend/public');
// ###############################################################


// Add Error Middleware (for development)
$app->addErrorMiddleware(true, true, true);

// Define CORS middleware
$app->add(function (Request $request, RequestHandler $handler): Response {
    $response = $handler->handle($request);
    return $response
        ->withHeader('Access-Control-Allow-Origin', '*')
        ->withHeader('Access-Control-Allow-Headers', 'X-Requested-With, Content-Type, Accept, Origin, Authorization')
        ->withHeader('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE, PATCH, OPTIONS');
});

// Handle OPTIONS requests (for CORS preflight)
$app->options('/{routes:.+}', function (Request $request, Response $response): Response {
    return $response;
});

// ###############################################################
// TEST-ROUTE ZUR FEHLERSUCHE (beibehalten)
// ###############################################################
$app->get('/debug-test', function (Request $request, Response $response) {
