use Slim\Factory\AppFactory;
use DI\Container;
use Dotenv\Dotenv;
use Psr\Container\ContainerInterface; // <<< NEU: Füge dies hinzu!

require __DIR__ . '/../vendor/autoload.php';

// Load .env file
if (file_exists(__DIR__ . '/../.env')) {
    $dotenv = Dotenv::createImmutable(__DIR__ . '/../');
    $dotenv->load(); // Lädt die Variablen in $_ENV und getenv()
}

// Create Container
$container = new Container();
AppFactory::setContainer($container);

// ###############################################################
// Datenbank-Parameter als separate Container-Einträge definieren (bleibt so)
// ###############################################################
$container->set('db.host', function () {
    return $_ENV['DB_HOST'] ?? 'localhost';
});
$container->set('db.name', function () {
    return $_ENV['DB_NAME'] ?? 'gdl_ui_studio_db';
});
$container->set('db.user', function () {
    return $_ENV['DB_USER'] ?? 'root';
});
$container->set('db.password', function () {
    return $_ENV['DB_PASSWORD'] ?? 'root';
});
// ###############################################################


// ###############################################################
// ANPASSUNG: db-Service Factory Closure erhält den Container selbst
// ###############################################################
$container->set('db', function (ContainerInterface $c) { // <<< Hier den Container injizieren!
    $dbHost = $c->get('db.host');      // Werte explizit aus dem Container holen
    $dbName = $c->get('db.name');
    $dbUser = $c->get('db.user');
    $dbPassword = $c->get('db.password');

    $dsn = "mysql:host={$dbHost};dbname={$dbName};charset=utf8mb4";
    $pdo = new PDO($dsn, $dbUser, $dbPassword);
    $pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
    $pdo->setAttribute(PDO::ATTR_DEFAULT_FETCH_MODE, PDO::FETCH_ASSOC);
    return $pdo;
}); // <<< HIER ENDET DIE DEFINITION, OHNE addArguments()
// ###############################################################


$app = AppFactory::create();

// ###############################################################
// KRITISCH: Slims Basis-Pfad explizit setzen (Beibehalten)
